code = """import json
import re

# Step 1: Get all UNIV CALIFORNIA patents and their CPC codes
uc_file = var_functions.query_db:78
with open(uc_file, 'r') as f:
    uc_data = json.load(f)

print(f"Total UNIV CALIFORNIA patents: {len(uc_data)}")

# Extract UC patent information
uc_patents = {}
uc_cpc_codes = set()

for record in uc_data:
    patents_info = record.get('Patents_info', '')
    
    # Extract UC publication number
    match = re.search(r'(US|WO|EP|JP|CN|TW|KR|DE|GB|FR)-[A-Z0-9-]+-A[0-9]*', patents_info)
    if match:
        pub_num = match.group(0)
        
        # Parse CPC codes
        cpc_data = record.get('cpc', '[]')
        cpc_codes = []
        try:
            cpc_list = json.loads(cpc_data)
            cpc_codes = [item.get('code') for item in cpc_list if item.get('code')]
            uc_cpc_codes.update(cpc_codes)
        except:
            pass
        
        uc_patents[pub_num] = {
            'patents_info': patents_info,
            'cpc_codes': cpc_codes
        }

print(f"Extracted {len(uc_patents)} UC patents with CPC codes")
print(f"Total unique CPC codes: {len(uc_cpc_codes)}")
print(f"Sample UC patents: {list(uc_patents.keys())[:5]}")

result = {
    'uc_patent_count': len(uc_patents),
    'unique_cpc_codes': len(uc_cpc_codes),
    'sample_cpc': list(uc_cpc_codes)[:10]
}

print('__RESULT__:')
print(json.dumps(result))"""

